  (0, 'pain_rest_p0', 'Боль в покое в пределах согласованного с куратором уровня (проверяет куратор)', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 50::smallint, FALSE),
